// ─────────────────────────────────────────────────────────────
// Read existing questions, merge, and write output
// ─────────────────────────────────────────────────────────────
const fs = require('fs');

// Try reading the most recent file; fall back gracefully
let existing = {};
const candidates = ['questions_batch2.json', 'questions_updated.json', 'questions.json'];
for (const f of candidates) {
    if (fs.existsSync(f)) {
        existing = JSON.parse(fs.readFileSync(f, 'utf8'));
        console.log(`✓ Loaded existing questions from: ${f}`);
        break;
    }
}

// Merge new questions
for (const section of Object.keys(newQuestions)) {
    if (!existing[section]) {
        existing[section] = [];
    }

    // Build a set of existing IDs for duplicate detection
    const existingIds = new Set(existing[section].map(q => q.id));

    let added = 0;
    let skipped = 0;
    for (const q of newQuestions[section]) {
        if (existingIds.has(q.id)) {
            skipped++;
        } else {
            existing[section].push(q);
            existingIds.add(q.id);
            added++;
        }
    }
    console.log(`  ${section}: +${added} added, ${skipped} skipped (duplicate IDs)`);
}

// Write output
fs.writeFileSync('questions_batch3.json', JSON.stringify(existing, null, 2));

console.log('\n✓ Done! questions_batch3.json created.');
console.log('\nSummary:');
for (const section of Object.keys(existing)) {
    const byLevel = { 1: 0, 2: 0, 3: 0 };
    for (const q of existing[section]) {
        byLevel[q.level] = (byLevel[q.level] || 0) + 1;
    }
    console.log(`  ${section}: ${existing[section].length} total | L1: ${byLevel[1]}, L2: ${byLevel[2]}, L3: ${byLevel[3]}`);
}
module.exports = newQuestions;